$outputDir = "C:\Users\Dyme\Documents\E-Commerce\templates\world-coiffure\site\assets\images"
$successCount = 0
$failCount = 0

foreach ($img in $images) {
    $outputPath = Join-Path $outputDir $img.Name
    try {
        Invoke-WebRequest -Uri $img.Url -OutFile $outputPath -UseBasicParsing -TimeoutSec 30
        $fileInfo = Get-Item $outputPath
        Write-Host "OK: $($img.Name) ($($fileInfo.Length) bytes)"
        $successCount++
    } catch {
        Write-Host "FAIL: $($img.Name) - $($_.Exception.Message)"
        $failCount++
    }
}

Write-Host "`n=== Summary ==="
Write-Host "Downloaded: $successCount"
Write-Host "Failed: $failCount"
